/// <summary>
/// this class will handle voyage lines costing transactions
/// </summary>
public final class ETGITMLineCostTransLinkClassOut
{
}

Method.Source:
private void createSalesLineLinkFromCostTrans(ITMCostTrans _shipCostTrans)
{
    ITMLineCostTransLink shipLineCostTransLink;
    ITMLine shipLine;

    RecId costTransRecId = _shipCostTrans.RecId;

    insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
        select RecId, costTransRecId from shipLine
            where shipLine.RefTableId == _shipCostTrans.TransTableId
               && shipLine.RefRecId == _shipCostTrans.TransRecId;
}

public void createShipCostTransLinkFromShipId(ITMId _shipId)
{
    if (_shipId != '')
    {
        ITMLineCostTransLink shipLineCostTransLink;
        ITMCostTrans shipCostTrans;
        ITMLine shipLine;

        insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
            select RecId from shipLine
                where shipLine.ShipId == _shipId
            join RecId from shipCostTrans
                where shipCostTrans.TransTableId == shipLine.RefTableId
                   && shipCostTrans.TransRecId == shipLine.RefRecId
            notexists join shipLineCostTransLink
                where shipLineCostTransLink.ShipLineRecId == shipLine.RecId
                   && shipLineCostTransLink.CostTransRecId == shipCostTrans.RecId;
    }
}

private void createSalesTableLinkFromCostTrans(ITMCostTrans _shipCostTrans)
{
    ITMLineCostTransLink shipLineCostTransLink;
    ITMLine shipLine;
    SalesTable salesTable;

    RecId costTransRecId = _shipCostTrans.RecId;

    insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
        select RecId, costTransRecId from shipLine
        where shipLine.TransType == InventTransType::Sales
            exists join salesTable
            where salesTable.SalesId == shipLine.TransRefId
               && salesTable.dataAreaId == shipLine.ShipDataArea
               && salesTable.TableId == _shipCostTrans.TransTableId
               && salesTable.RecId == _shipCostTrans.TransRecId;
}

