{
    ITMLineCostTransLink shipLineCostTransLink;
    ITMCostTrans shipCostTrans;
    SalesTable salesTable;

    RecId shipLineRecId = _shipLine.RecId;

    insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
        select shipLineRecId, RecId from shipCostTrans
            exists join salesTable
            where salesTable.TableId == shipCostTrans.TransTableId
               && salesTable.RecId == shipCostTrans.TransRecId
               && salesTable.SalesId == _shipLine.TransRefId
               && salesTable.dataAreaId == _shipLine.ShipDataArea;
}

public void createSalesTableLinkFromShipId(ITMId _shipId)
{
    if (_shipId != '')
    {
        ITMLineCostTransLink shipLineCostTransLink;
        ITMCostTrans shipCostTrans;
        SalesTable salesTable;
        ITMLine shipLine;

        insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
            select RecId from shipLine
                where shipLine.ShipId == _shipId
            join RecId from shipCostTrans
                exists join salesTable
                where salesTable.TableId == shipCostTrans.TransTableId
                   && salesTable.RecId == shipCostTrans.TransRecId
                   && salesTable.SalesId == shipLine.TransRefId
            notexists join shipLineCostTransLink
                where shipLineCostTransLink.ShipLineRecId == shipLine.RecId
                   && shipLineCostTransLink.CostTransRecId == shipCostTrans.RecId;;
    }
}

private void createShipContainersLinkFromCostTrans(ITMCostTrans _shipCostTrans)
{
    ITMLineCostTransLink shipLineCostTransLink;
    ITMLine shipLine;
    ITMContainers shipContainers;

    RecId costTransRecId = _shipCostTrans.RecId;

    insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
        select RecId, costTransRecId from shipLine
            exists join shipContainers
            where shipContainers.ShipId == shipLine.ShipId 
               && shipContainers.ShipContainerId == shipLine.ShipContainerId
               && shipContainers.TableId == _shipCostTrans.TransTableId
               && shipContainers.RecId == _shipCostTrans.TransRecId;
}

