public void createShipFolioTableLinkFromShipIdAndFolioId(ITMId _shipId, ITMFolioId _folioId)
{
    if (_shipId != '' && _folioId != '')
    {
        ITMLineCostTransLink shipLineCostTransLink;
        ITMCostTrans shipCostTrans;
