}

private void createShipTableLinkFromCostTrans(ITMCostTrans _shipCostTrans)
{
    ITMLineCostTransLink shipLineCostTransLink;
    ITMLine shipLine;
    ITMTable shipTable;

    RecId costTransRecId = _shipCostTrans.RecId;

    insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
        select RecId, costTransRecId from shipLine
            exists join shipTable
            where shipTable.ShipId == shipLine.ShipId 
               && shipTable.TableId == _shipCostTrans.TransTableId
               && shipTable.RecId == _shipCostTrans.TransRecId;
}

private void createShipTableLinkFromShipLine(ITMLine _shipLine)
{
    ITMLineCostTransLink shipLineCostTransLink;
    ITMCostTrans shipCostTrans;
    ITMTable shipTable;

    RecId shipLineRecId = _shipLine.RecId;

    insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
        select shipLineRecId, RecId from shipCostTrans
            exists join shipTable
            where shipTable.TableId == shipCostTrans.TransTableId
               && shipTable.RecId == shipCostTrans.TransRecId
               && shipTable.ShipId == _shipLine.ShipId;
}

public void createShipTableLinkFromShipId(ITMId _shipId)
{    
    if (_shipId != '')
    {
        ITMLineCostTransLink shipLineCostTransLink;
        ITMCostTrans shipCostTrans;
        ITMTable shipTable;
        ITMLine  shipLine;

        insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
            select RecId from shipLine
                where shipLine.ShipId == _shipId
            join RecId from shipCostTrans
                exists join shipTable
                where shipTable.TableId == shipCostTrans.TransTableId
                   && shipTable.RecId == shipCostTrans.TransRecId
                   && shipTable.ShipId == _shipId
                notexists join shipLineCostTransLink
                where shipLineCostTransLink.ShipLineRecId == shipLine.RecId
                   && shipLineCostTransLink.CostTransRecId == shipCostTrans.RecId;
    }
}

public void insertLinksFromShipCostTrans(ITMCostTrans _shipCostTrans)
{
    switch (_shipCostTrans.TransTableId)
    {
        case tableNum(ITMTable):
            this.createShipTableLinkFromCostTrans(_shipCostTrans);
            break;

        case tableNum(ITMContainers):
            this.createShipContainersLinkFromCostTrans(_shipCostTrans);
            break;

        case tableNum(ITMFolioTable):
            this.createShipFolioTableLinkFromCostTrans(_shipCostTrans);
            break;

        case tableNum(SalesTable):
            this.createSalesTableLinkFromCostTrans(_shipCostTrans);
            break;

        case tableNum(SalesLine):
        case tableNum(InventTransferLine):
            this.createSalesLineLinkFromCostTrans(_shipCostTrans);
            break;
    }
}

public void insertLinksFromShipLine(ITMLine _shipLine)
{
    this.createShipTableLinkFromShipLine(_shipLine);

    if (_shipLine.ShipContainerId)
    {
        this.createShipContainersLinkFromShipLine(_shipLine);
    }
    if (_shipLine.ShipFolioId)
    {
        this.createShipFolioTableLinkFromShipLine(_shipLine);
    }
    switch (_shipLine.RefTableId)
    {
        case tableNum(SalesLine):
            this.createSalesTableLinkFromShipLine(_shipLine);
            break;
    }

    this.createSalesLineLinkFromShipLine(_shipLine);
}

private void createSalesLineLinkFromShipLine(ITMLine _shipLine)
{
    ITMLineCostTransLink shipLineCostTransLink;
    ITMCostTrans shipCostTrans;

    RecId shipLineRecId = _shipLine.RecId;

    insert_recordset shipLineCostTransLink(ShipLineRecId, CostTransRecId)
        select shipLineRecId, RecId from shipCostTrans
            where shipCostTrans.TransTableId == _shipLine.RefTableId
               && shipCostTrans.TransRecId == _shipLine.RefRecId;
}

protected void new()
{
}

internal void updateLinksFromShipLine(ITMLine _shipLine)
{
    ITMLine shipLine_Orig = _shipLine.orig();

    ITMLineCostTransLink shipLineCostTransLink;
    ITMCostTrans shipCostTrans;

    if (_shipLine.ShipContainerId != shipLine_Orig.ShipContainerId)
    {
        if (shipLine_Orig.ShipContainerId)
        {
            delete_from shipLineCostTransLink
                exists join shipCostTrans
                where shipCostTrans.RecId == shipLineCostTransLink.CostTransRecId
                   && shipCostTrans.TransTableId == tableNum(ITMContainers);
        }

        if (_shipLine.ShipContainerId)
        {
            this.createShipContainersLinkFromShipLine(_shipLine);
        }
    }

    if (_shipLine.ShipFolioId != shipLine_Orig.ShipFolioId)
    {
        if (shipLine_Orig.ShipFolioId)
        {
            delete_from shipLineCostTransLink
                exists join shipCostTrans
                where shipCostTrans.RecId == shipLineCostTransLink.CostTransRecId &&
                      shipCostTrans.TransTableId == tableNum(ITMFolioTable);
        }

        if (_shipLine.ShipFolioId)
        {
            this.createShipFolioTableLinkFromShipLine(_shipLine);
        }
    }
}

internal static ETGITMLineCostTransLinkClassOut construct()
{
    return new ETGITMLineCostTransLinkClassOut();
}
